import{_ as e,o as l,c as o,ae as n}from"./chunks/framework.C7FLYIpo.js";const w=JSON.parse('{"title":"채팅 채널","description":"OpenClaw이 연결할 수 있는 메시징 플랫폼","frontmatter":{"title":"채팅 채널","description":"OpenClaw이 연결할 수 있는 메시징 플랫폼"},"headers":[],"relativePath":"channels/index.md","filePath":"channels/index.md","lastUpdated":null}'),c={name:"channels/index.md"};function i(s,a,t,r,h,d){return l(),o("div",null,[...a[0]||(a[0]=[n('<h1 id="채팅-채널" tabindex="-1">채팅 채널 <a class="header-anchor" href="#채팅-채널" aria-label="Permalink to &quot;채팅 채널&quot;">​</a></h1><p>OpenClaw는 이미 사용 중인 채팅 앱과 통신할 수 있습니다. 각 채널은 게이트웨이를 통해 연결됩니다. 텍스트는 모든 채널에서 지원되며, 미디어 및 반응 기능은 채널마다 다릅니다.</p><h2 id="지원되는-채널" tabindex="-1">지원되는 채널 <a class="header-anchor" href="#지원되는-채널" aria-label="Permalink to &quot;지원되는 채널&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/channels/bluebubbles">BlueBubbles</a> — <strong>iMessage에 권장</strong>; 전체 기능을 지원하는 BlueBubbles macOS 서버 REST API를 사용합니다(번들 플러그인; 편집, 전송 취소, 효과, 반응, 그룹 관리 — macOS 26 Tahoe에서 편집 기능 현재 작동 불가).</li><li><a href="/openclaw-docs-ko/channels/discord">Discord</a> — Discord Bot API + 게이트웨이; 서버, 채널, DM을 지원합니다.</li><li><a href="/openclaw-docs-ko/channels/feishu">Feishu</a> — WebSocket을 통한 Feishu/Lark 봇(번들 플러그인).</li><li><a href="/openclaw-docs-ko/channels/googlechat">Google Chat</a> — HTTP 웹훅을 통한 Google Chat API 앱.</li><li><a href="/openclaw-docs-ko/channels/imessage">iMessage (레거시)</a> — imsg CLI를 통한 레거시 macOS 연동(더 이상 사용되지 않음, 새 설정에는 BlueBubbles 사용 권장).</li><li><a href="/openclaw-docs-ko/channels/irc">IRC</a> — 클래식 IRC 서버; 채널 + DM, 페어링/허용 목록 제어.</li><li><a href="/openclaw-docs-ko/channels/line">LINE</a> — LINE Messaging API 봇(번들 플러그인).</li><li><a href="/openclaw-docs-ko/channels/matrix">Matrix</a> — Matrix 프로토콜(번들 플러그인).</li><li><a href="/openclaw-docs-ko/channels/mattermost">Mattermost</a> — Bot API + WebSocket; 채널, 그룹, DM(번들 플러그인).</li><li><a href="/openclaw-docs-ko/channels/msteams">Microsoft Teams</a> — Bot Framework; 엔터프라이즈 지원(번들 플러그인).</li><li><a href="/openclaw-docs-ko/channels/nextcloud-talk">Nextcloud Talk</a> — Nextcloud Talk를 통한 자체 호스팅 채팅(번들 플러그인).</li><li><a href="/openclaw-docs-ko/channels/nostr">Nostr</a> — NIP-04를 통한 분산형 DM(번들 플러그인).</li><li><a href="/openclaw-docs-ko/channels/qqbot">QQ Bot</a> — QQ Bot API; 개인 채팅, 그룹 채팅, 리치 미디어(번들 플러그인).</li><li><a href="/openclaw-docs-ko/channels/signal">Signal</a> — signal-cli; 프라이버시 중심.</li><li><a href="/openclaw-docs-ko/channels/slack">Slack</a> — Bolt SDK; 워크스페이스 앱.</li><li><a href="/openclaw-docs-ko/channels/synology-chat">Synology Chat</a> — 발신/수신 웹훅을 통한 Synology NAS Chat(번들 플러그인).</li><li><a href="/openclaw-docs-ko/channels/telegram">Telegram</a> — grammY를 통한 Bot API; 그룹을 지원합니다.</li><li><a href="/openclaw-docs-ko/channels/tlon">Tlon</a> — Urbit 기반 메신저(번들 플러그인).</li><li><a href="/openclaw-docs-ko/channels/twitch">Twitch</a> — IRC 연결을 통한 Twitch 채팅(번들 플러그인).</li><li><a href="/openclaw-docs-ko/plugins/voice-call">음성 통화</a> — Plivo 또는 Twilio를 통한 전화(플러그인, 별도 설치 필요).</li><li><a href="/openclaw-docs-ko/web/webchat">WebChat</a> — WebSocket을 통한 게이트웨이 WebChat UI.</li><li><a href="https://www.npmjs.com/package/@tencent-weixin/openclaw-weixin" target="_blank" rel="noreferrer">WeChat</a> — QR 로그인을 통한 Tencent iLink 봇 플러그인; 개인 채팅만 지원.</li><li><a href="/openclaw-docs-ko/channels/whatsapp">WhatsApp</a> — 가장 인기 있는 채널; Baileys를 사용하며 QR 페어링이 필요합니다.</li><li><a href="/openclaw-docs-ko/channels/zalo">Zalo</a> — Zalo Bot API; 베트남의 인기 메신저(번들 플러그인).</li><li><a href="/openclaw-docs-ko/channels/zalouser">Zalo 개인</a> — QR 로그인을 통한 Zalo 개인 계정(번들 플러그인).</li></ul><h2 id="참고-사항" tabindex="-1">참고 사항 <a class="header-anchor" href="#참고-사항" aria-label="Permalink to &quot;참고 사항&quot;">​</a></h2><ul><li>채널은 동시에 실행할 수 있습니다. 여러 채널을 구성하면 OpenClaw가 채팅별로 라우팅합니다.</li><li>가장 빠른 설정은 일반적으로 <strong>Telegram</strong>입니다(간단한 봇 토큰). WhatsApp은 QR 페어링이 필요하고 디스크에 더 많은 상태를 저장합니다.</li><li>그룹 동작은 채널마다 다릅니다. <a href="/openclaw-docs-ko/channels/groups">그룹</a>을 참조하십시오.</li><li>DM 페어링 및 허용 목록은 보안을 위해 적용됩니다. <a href="/openclaw-docs-ko/gateway/security">보안</a>을 참조하십시오.</li><li>문제 해결: <a href="/openclaw-docs-ko/channels/troubleshooting">채널 문제 해결</a>.</li><li>모델 프로바이더는 별도로 문서화되어 있습니다. <a href="/openclaw-docs-ko/providers/models">모델 프로바이더</a>를 참조하십시오.</li></ul>',6)])])}const k=e(c,[["render",i]]);export{w as __pageData,k as default};
